modules.fpm_unpack:
`timescale 1ns/1ps
module fpm_unpack(
    input  [31:0] a,
    input  [31:0] b,
    output        a_sign,
    output [7:0]  a_exp,
    output [23:0] a_mant,
    output        b_sign,
    output [7:0]  b_exp,
    output [23:0] b_mant,
    output        a_is_nan,
    output        a_is_inf,
    output        a_is_zero,
    output        b_is_nan,
    output        b_is_inf,
    output        b_is_zero
);
    // Unpack a
    assign a_sign = a[31];
    assign a_exp  = a[30:23];
    // mantissa: implicit leading 1 for normal numbers, no implicit 1 for denormals
    assign a_mant = (a[30:23] == 8'h00) ? {1'b0, a[22:0]}  // denormal: no implicit 1
                                         : {1'b1, a[22:0]}; // normal: implicit 1

    wire a_exp_all_ones = (a[30:23] == 8'hFF);
    wire a_mant_nonzero = (a[22:0] != 23'h0);
    assign a_is_nan  = a_exp_all_ones & a_mant_nonzero;
    assign a_is_inf  = a_exp_all_ones & ~a_mant_nonzero;
    assign a_is_zero = (a[30:0] == 31'h0); // exp=0 and mant=0 (sign ignored)

    // Unpack b
    assign b_sign = b[31];
    assign b_exp  = b[30:23];
    assign b_mant = (b[30:23] == 8'h00) ? {1'b0, b[22:0]}
                                         : {1'b1, b[22:0]};

    wire b_exp_all_ones = (b[30:23] == 8'hFF);
    wire b_mant_nonzero = (b[22:0] != 23'h0);
    assign b_is_nan  = b_exp_all_ones & b_mant_nonzero;
    assign b_is_inf  = b_exp_all_ones & ~b_mant_nonzero;
    assign b_is_zero = (b[30:0] == 31'h0);

endmodule

modules.fpm_multiply:
`timescale 1ns/1ps
module fpm_multiply(
    input         a_sign,
    input  [7:0]  a_exp,
    input  [23:0] a_mant,
    input         b_sign,
    input  [7:0]  b_exp,
    input  [23:0] b_mant,
    output        result_sign,
    output [47:0] product,
    output [9:0]  raw_exp
);
    assign result_sign = a_sign ^ b_sign;
    assign product     = a_mant * b_mant;
    assign raw_exp     = {2'b00, a_exp} + {2'b00, b_exp} - 10'd127;
endmodule

modules.fpm_normalize:
`timescale 1ns/1ps
module fpm_normalize(
    input  [47:0] product,
    input  [9:0]  raw_exp,
    output [22:0] norm_frac,
    output [9:0]  norm_exp,
    output        guard,
    output        sticky
);
    wire overflow = product[47];

    // When overflow (bit47=1): shift right by 1
    //   frac = bits[46:24], guard = bit[23], sticky = OR(bits[22:0])
    // When no overflow (bit47=0): 
    //   frac = bits[45:23], guard = bit[22], sticky = OR(bits[21:0])

    assign norm_frac = overflow ? product[46:24] : product[45:23];
    assign norm_exp  = overflow ? raw_exp + 10'd1 : raw_exp;
    assign guard     = overflow ? product[23]     : product[22];
    assign sticky    = overflow ? |product[22:0]  : |product[21:0];

endmodule

modules.fpm_round_pack:
// full module source
`timescale 1ns/1ps
module fpm_round_pack(
    input         sign,
    input  [22:0] norm_frac,
    input  [9:0]  norm_exp,
    input         guard,
    input         sticky,
    output reg [31:0] result,
    output reg        overflow,
    output reg        underflow
);
    wire round_up;
    wire [23:0] frac_rounded;
    wire [9:0]  exp_adjusted;
    wire [22:0] final_frac;
    wire [9:0]  final_exp;

    // Round to nearest even
    // Round up if: guard=1 AND (sticky=1 OR frac[0]=1)
    assign round_up = guard & (sticky | norm_frac[0]);

    // Add round bit to fraction
    assign frac_rounded = {1'b0, norm_frac} + {23'b0, round_up};

    // If rounding caused overflow of mantissa (bit 23 set), increment exponent
    assign exp_adjusted = norm_exp + (frac_rounded[23] ? 10'd1 : 10'd0);

    // Final fraction: if mantissa overflowed due to rounding, shift right (becomes 0)
    assign final_frac = frac_rounded[23] ? frac_rounded[23:1] : frac_rounded[22:0];

    // Final exponent
    assign final_exp = exp_adjusted;

    always @(*) begin
        overflow  = 0;
        underflow = 0;
        result    = 0;

        // norm_exp is 10-bit, may be signed (two's complement)
        // If bit 9 is set, it's a negative exponent => underflow
        if (norm_exp[9]) begin
            // Negative exponent: underflow to zero
            underflow = 1;
            result    = 0;
        end else if (norm_exp == 10'd0) begin
            // Zero exponent: underflow
            underflow = 1;
            result    = 0;
        end else if (norm_exp >= 10'd255) begin
            // Overflow: result is infinity
            overflow = 1;
            result   = {sign, 8'hFF, 23'h0};
        end else begin
            // Check after rounding if exponent overflows
            if (final_exp >= 10'd255) begin
                overflow = 1;
                result   = {sign, 8'hFF, 23'h0};
            end else if (final_exp == 10'd0 || final_exp[9]) begin
                underflow = 1;
                result    = 0;
            end else begin
                result = {sign, final_exp[7:0], final_frac};
            end
        end
    end

endmodule

modules.fpm_special:
`timescale 1ns/1ps
module fpm_special(
    input         a_is_nan,
    input         a_is_inf,
    input         a_is_zero,
    input         b_is_nan,
    input         b_is_inf,
    input         b_is_zero,
    input         result_sign,
    output        is_special,
    output reg [31:0] special_result
);
    // Special case detection
    wire is_nan_result  = a_is_nan | b_is_nan | (a_is_inf & b_is_zero) | (a_is_zero & b_is_inf);
    wire is_inf_result  = (a_is_inf | b_is_inf) & ~is_nan_result;
    wire is_zero_result = (a_is_zero | b_is_zero) & ~is_nan_result;

    assign is_special = is_nan_result | is_inf_result | is_zero_result;

    always @(*) begin
        if (is_nan_result)
            special_result = 32'h7FC00000; // Quiet NaN
        else if (is_inf_result)
            special_result = {result_sign, 8'hFF, 23'h0}; // Signed Inf
        else if (is_zero_result)
            special_result = {result_sign, 31'h0}; // Signed Zero
        else
            special_result = 32'h0;
    end
endmodule
